const input = $items('Build Insert Prompt')[0].json;
const raw = $json.response !== undefined ? $json.response : JSON.stringify($json);
let parsed = null;
try {
  let text = typeof raw === 'string' ? raw : JSON.stringify(raw);
  // Strip markdown fences
  text = text.replace(/```json?\s*/gi, '').replace(/```/g, '');
  // Find first { to last }
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    parsed = JSON.parse(text.slice(start, end + 1));
  } else {
    parsed = JSON.parse(text.trim());
  }
} catch (e) {
  parsed = null;
}
// Normalize or fall back
let title, content, tags;
if (parsed && typeof parsed === 'object') {
  title = (parsed.title || '').trim().slice(0, 100);
  content = (parsed.content || '').trim();
  tags = parsed.tags;
  // Normalize tags
  if (typeof tags === 'string') {
    tags = tags.split(',').map(t => t.trim().toLowerCase()).filter(Boolean);
  }
  if (!Array.isArray(tags) || tags.length === 0) {
    tags = ['untagged'];
  } else {
    tags = tags.map(t => String(t).toLowerCase().trim()).filter(Boolean);
    if (tags.length === 0) tags = ['untagged'];
  }
  if (!title) title = (input.prompt_text || '').slice(0, 60);
  if (!content) content = input.prompt_text || '';
} else {
  // Full fallback
  title = (input.prompt_text || '').slice(0, 60);
  content = input.prompt_text || '';
  tags = ['untagged'];
}
const noteId = Date.now().toString(36) + '-' + Math.random().toString(36).substr(2, 9);
return [{ json: { ...input, noteId, title, content, tags } }];

const input = $json;
const now = new Date().toISOString();
const project = input.project_name;
const graph = 'SpecGraph';
const noteId = input.noteId;
const title = input.title;
const content = input.content;
const tags = input.tags || ['untagged'];

// Statement 1: MERGE SpecNote
const noteStatement = {
  statement: [
    'MERGE (n:SpecNote {noteId: $noteId, project: $project, graph: $graph})',
    'SET n.title = $title, n.content = $content, n.tags = $tags, n.createdAt = $now, n.updatedAt = $now'
  ].join(' '),
  parameters: {
    noteId: noteId,
    project: project,
    graph: graph,
    title: title,
    content: content,
    tags: tags,
    now: now
  }
};

// Additional statements: one per tag — MERGE SpecTag + TAGGED_WITH relationship
const tagStatements = tags.map(tag => ({
  statement: [
    'MATCH (n:SpecNote {noteId: $noteId, graph: $graph})',
    'MERGE (t:SpecTag {name: $tag, project: $project, graph: $graph})',
    'MERGE (n)-[:TAGGED_WITH]->(t)'
  ].join(' '),
  parameters: {
    noteId: noteId,
    tag: tag,
    project: project,
    graph: graph
  }
}));

// INSTANCE_OF link to parent class hub node
const noteClassStatement = {
  statement: [
    'MATCH (n:SpecNote {noteId: $noteId, graph: $graph})',
    "MERGE (c:SpecClass {name: 'SpecNote', graph: $graph})",
    'MERGE (n)-[:INSTANCE_OF]->(c)'
  ].join(' '),
  parameters: { noteId: noteId, graph: graph }
};
const neo4jBody = { statements: [noteStatement, ...tagStatements, noteClassStatement] };
return [{ json: { ...input, neo4jBody } }];
